import{_ as e,o as t,c as n,ag as s}from"./chunks/framework.CAXxHpAX.js";const _=JSON.parse('{"title":"概述","description":"Node Push Exporter 项目概述","frontmatter":{"title":"概述","description":"Node Push Exporter 项目概述"},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),d={name:"guide/index.md"};function o(r,a,p,l,i,c){return t(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>Node Push Exporter 是一个用于采集系统指标并推送到 Prometheus Pushgateway 的轻量级服务。它作为 <code>node_exporter</code> 的包装器，自动管理 <code>node_exporter</code> 子进程，并按配置的间隔将采集的指标推送到 Pushgateway。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="_1-指标采集与推送" tabindex="-1">1. 指标采集与推送 <a class="header-anchor" href="#_1-指标采集与推送" aria-label="Permalink to &quot;1. 指标采集与推送&quot;">​</a></h3><ul><li><strong>node_exporter 指标</strong>: 自动采集 CPU、内存、磁盘、网络等标准系统指标</li><li><strong>自定义 GPU 指标</strong>: 支持 NVIDIA 和 AMD ROCm GPU 的温度、功耗、显存、利用率等指标</li><li><strong>定时推送</strong>: 可配置的推送间隔（默认 30 秒），自动推送到 Pushgateway</li></ul><h3 id="_2-节点管理" tabindex="-1">2. 节点管理 <a class="header-anchor" href="#_2-节点管理" aria-label="Permalink to &quot;2. 节点管理&quot;">​</a></h3><ul><li><strong>自动注册</strong>: 启动时自动向管理服务注册节点信息</li><li><strong>心跳机制</strong>: 定期发送心跳，报告节点状态和推送结果</li><li><strong>状态监控</strong>: 支持在线 (online)、降级 (degraded)、离线 (offline) 三种状态</li></ul><h3 id="_3-二进制分发服务" tabindex="-1">3. 二进制分发服务 <a class="header-anchor" href="#_3-二进制分发服务" aria-label="Permalink to &quot;3. 二进制分发服务&quot;">​</a></h3><p>配套的 <strong>Binary Download Service</strong> 提供：</p><ul><li>二进制文件上传、存储、分发</li><li>多平台、多架构版本管理</li><li>Web 管理界面</li><li>RESTful API</li></ul><h2 id="架构图" tabindex="-1">架构图 <a class="header-anchor" href="#架构图" aria-label="Permalink to &quot;架构图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      Prometheus/Grafana                      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                              ▲</span></span>
<span class="line"><span>                              │ Pull</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Prometheus Pushgateway                    │</span></span>
<span class="line"><span>│                    (接收来自各节点的推送)                      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                              ▲</span></span>
<span class="line"><span>                              │ Push</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  node-push-exporter (每节点)                  │</span></span>
<span class="line"><span>│  ┌─────────────┐  ┌─────────────┐  ┌─────────────────────┐  │</span></span>
<span class="line"><span>│  │   指标采集    │  │   指标推送    │  │   GPU 指标采集      │  │</span></span>
<span class="line"><span>│  └─────────────┘  └─────────────┘  └─────────────────────┘  │</span></span>
<span class="line"><span>│         │                                          │         │</span></span>
<span class="line"><span>│         ▼                                          ▼         │</span></span>
<span class="line"><span>│  ┌─────────────┐                          ┌─────────────────┐│</span></span>
<span class="line"><span>│  │node_exporter│                          │nvidia-smi/rocm-smi│</span></span>
<span class="line"><span>│  └─────────────┘                          └─────────────────┘│</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>                              │ Register/Heartbeat</span></span>
<span class="line"><span>                              ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                   Binary Download Service                    │</span></span>
<span class="line"><span>│                   (节点注册与监控管理)                         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="支持的指标" tabindex="-1">支持的指标 <a class="header-anchor" href="#支持的指标" aria-label="Permalink to &quot;支持的指标&quot;">​</a></h2><h3 id="系统指标-node-exporter" tabindex="-1">系统指标 (node_exporter) <a class="header-anchor" href="#系统指标-node-exporter" aria-label="Permalink to &quot;系统指标 (node_exporter)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类别</th><th>指标示例</th></tr></thead><tbody><tr><td>CPU</td><td><code>node_cpu_seconds_total</code>, <code>node_load1</code></td></tr><tr><td>内存</td><td><code>node_memory_MemTotal_bytes</code>, <code>node_memory_MemAvailable_bytes</code></td></tr><tr><td>磁盘</td><td><code>node_disk_read_bytes_total</code>, <code>node_filesystem_avail_bytes</code></td></tr><tr><td>网络</td><td><code>node_network_receive_bytes_total</code>, <code>node_network_transmit_bytes_total</code></td></tr></tbody></table><h3 id="自定义-gpu-指标" tabindex="-1">自定义 GPU 指标 <a class="header-anchor" href="#自定义-gpu-指标" aria-label="Permalink to &quot;自定义 GPU 指标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类别</th><th>指标名称</th><th>说明</th></tr></thead><tbody><tr><td>采集状态</td><td><code>node_push_exporter_gpu_scrape_success</code></td><td>GPU 采集是否成功</td></tr><tr><td>设备数量</td><td><code>node_push_exporter_gpu_devices_detected</code></td><td>检测到的 GPU 设备数</td></tr><tr><td>温度</td><td><code>gpu_temperature_celsius</code></td><td>GPU 温度（℃）</td></tr><tr><td>利用率</td><td><code>gpu_utilization_percent</code></td><td>GPU 利用率（%）</td></tr><tr><td>显存</td><td><code>gpu_memory_used_percent</code>, <code>gpu_memory_used_bytes</code></td><td>显存使用情况</td></tr><tr><td>功耗</td><td><code>gpu_power_draw_watts</code></td><td>GPU 功耗（W）</td></tr></tbody></table><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>技术</th></tr></thead><tbody><tr><td>主程序</td><td>Go 1.21+</td></tr><tr><td>指标采集</td><td>node_exporter, nvidia-smi, rocm-smi</td></tr><tr><td>指标推送</td><td>Prometheus Pushgateway</td></tr><tr><td>管理服务</td><td>FastAPI + SQLite</td></tr><tr><td>文档站点</td><td>VitePress</td></tr></tbody></table>`,20)])])}const u=e(d,[["render",o]]);export{_ as __pageData,u as default};
